function validateEstimateQuoteSkeletonScope() {
  const skeleton = (estimateQuoteState.scopes || []).find(item => item.label === "골조성");
  if (!skeleton || !skeleton.checked) return true;
  return (skeleton.children || []).some(child => child.checked);
}

function saveEstimateQuoteDraft() {
  syncEstimateQuoteInputsToState();
  if (!validateEstimateQuoteSkeletonScope()) {
    showToast("골조성을 선택한 경우 가설, 단열, 견출, 방수턱 중 최소 1개를 선택해야 프로젝트 저장이 가능합니다.");
    renderEstimateQuoteScopeChips();
    return;
  }
  if (!estimateQuoteState.projectName) {
    showToast("프로젝트명을 입력해야 프로젝트를 저장할 수 있습니다.");
    return;
  }
  const record = JSON.parse(JSON.stringify(estimateQuoteState));
  if (estimateQuoteEditingIndex === null || estimateQuoteEditingIndex < 0) {
    estimateQuoteRecords.unshift(record);
  } else {
    estimateQuoteRecords[estimateQuoteEditingIndex] = record;
  }
  estimateQuoteEditingIndex = null;
  showToast("프로젝트 기록을 저장했습니다.");
  switchWorkPanel("estimateQuoteList");
}
function resetEstimateQuoteForm() {
  estimateQuoteState = JSON.parse(JSON.stringify(estimateQuoteDefaultData));
  estimateQuoteEditingIndex = null;
  renderEstimateQuoteDashboard();
  showToast("프로젝트 작성 화면을 초기화했습니다.");
}
function loadEstimateQuoteSample() {
  estimateQuoteState = JSON.parse(JSON.stringify(estimateQuoteSampleData));
  estimateQuoteEditingIndex = null;
  renderEstimateQuoteDashboard();
  showToast("포항 AI Factory 견적서 예시를 불러왔습니다.");
}
function renderEstimateQuoteList() {
  const body = document.getElementById("estimateQuoteListBody");
  if (!body) return;
  const keyword = (document.getElementById("estimateQuoteSearch")?.value || "").trim().toLowerCase();
  const status = document.getElementById("estimateQuoteStatusFilter")?.value || "전체";
  const rows = estimateQuoteRecords.filter(row => {
    const scopeText = (row.scopes || []).map(estimateQuoteScopeText).filter(Boolean).join(" ");
    const hay = [row.projectNo, row.projectName, row.client, row.requesterName, scopeText, row.areaM2, row.areaPy].join(" ").toLowerCase();
    return (!keyword || hay.includes(keyword)) && (status === "전체" || row.status === status || (status === "작성중" && row.status === "견적작성중"));
  });
  body.innerHTML = rows.map(row => {
    const index = estimateQuoteRecords.indexOf(row);
    const scopeText = (row.scopes || []).map(estimateQuoteScopeText).filter(Boolean).join(" · ") || "미선택";
    const areaText = [row.areaM2, row.areaPy].filter(Boolean).join(" / ") || "-";
    return `<tr onclick="editEstimateQuoteRecord(${index})">
      <td>${row.projectNo || "-"}</td>
      <td><strong>${row.projectName || "미입력"}</strong></td>
      <td>${row.client || "-"}</td>
      <td>${areaText}</td>
      <td>${row.floors || "-"}</td>
      <td>${scopeText}</td>
      <td>${row.requesterName || "-"}<br><small>${row.requesterEmail || ""}</small></td>
      <td><span class="quote-status-badge">${row.status || "작성중"}</span></td>
      <td class="quote-action-cell" onclick="event.stopPropagation();">
        <button class="btn btn-line btn-xs" type="button" onclick="editEstimateQuoteRecord(${index})">수정</button>
        <button class="btn btn-line btn-xs" type="button" onclick="markEstimateQuoteSent(${index})">발송</button>
        <button class="btn btn-primary btn-xs" type="button" onclick="startProjectFromEstimateQuote(${index})">착수</button>
      </td>
    </tr>`;
  }).join("") || `<tr><td colspan="9" class="empty-cell">조건에 맞는 견적서 기록이 없습니다.</td></tr>`;
}
function editEstimateQuoteRecord(index) {
  if (!estimateQuoteRecords[index]) return;
  estimateQuoteState = JSON.parse(JSON.stringify(estimateQuoteRecords[index]));
  estimateQuoteEditingIndex = index;
  switchWorkPanel("estimateQuote");
  renderEstimateQuoteDashboard();
}
function markEstimateQuoteSent(index) {
  if (!estimateQuoteRecords[index]) return;
  estimateQuoteRecords[index].status = "견적발송";
  renderEstimateQuoteList();
  showToast("견적서 발송 상태로 변경했습니다.");
}
function startProjectFromEstimateQuote(index) {
  const row = estimateQuoteRecords[index];
  if (!row) return;
  row.status = "착수확정";
  const parsed = parseProjectReceiveFloors(row.floors || "");
  projectReceiveState = JSON.parse(JSON.stringify({
    ...projectReceiveDefaultData,
    projectName: row.projectName,
    projectNo: row.projectNo,
    client: row.client,
    usage: row.usage,
    area: row.areaPy || row.areaM2,
    buildings: row.buildings,
    floors: row.floors,
    basementFloors: parsed.basementFloors,
    groundFloors: parsed.groundFloors,
    unitPrice: "프로젝트 관리에서 착수 전환",
    scopes: JSON.parse(JSON.stringify(row.scopes || projectReceiveDefaultData.scopes)),
    contacts: [{ name: row.requesterName, role: row.requesterDept, dept: "", tel: row.requesterPhone, mobile: row.requesterPhone, email: row.requesterEmail }],
    materials: createProjectReceiveDummyMaterials("프로젝트 관리"),
    workContent: `프로젝트 관리에서 착수 전환: ${row.structureContract || "구조 계약 미입력"} / ${row.finishContract || "마감 계약 미입력"}`,
    notes: row.notes,
    request: [row.callMemo, row.emailMemo, row.downloadUrl ? `자료주소: ${row.downloadUrl} / ID: ${row.webhardId} / PW: ${row.webhardPw} / KEY: ${row.accessKey}` : ""].filter(Boolean).join("\n\n")
  }));
  switchWorkPanel("projectReceive");
  renderProjectReceiveDashboard();
  showToast("견적서 기록을 프로젝트 작성 화면으로 불러왔습니다. 미비된 내용만 추가 작성하세요.");
}

/* =========================================================
   프로젝트 작성: DB관리(PJ관리) 행 불러오기
   - DB관리에서 작성한 PJ관리 행을 프로젝트 작성 화면으로 선택 반영
   - 동일/중복되는 항목만 자동 입력하고, 나머지는 기존 입력값 유지
========================================================= */
function getEstimateDbPjCell(row, headerName) {
  const aliases = { "부서명": "거래처", "수주시 요청사항": "상담 / 이메일 / 특기사항" };
  const primary = getEstimateDbColumnIndexByHeader("pj", headerName);
  const alias = aliases[headerName] ? getEstimateDbColumnIndexByHeader("pj", aliases[headerName]) : -1;
  const idx = primary >= 0 ? primary : alias;
  if (idx < 0) return "";
  return String(row?.[idx] || "").trim();
}

function normalizeEstimateQuoteDbText(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function setEstimateQuoteScopeByDbWorkType(workType) {
  const text = normalizeEstimateQuoteDbText(workType);
  if (!text || !Array.isArray(estimateQuoteState.scopes)) return;
  estimateQuoteState.scopes.forEach(item => {
    const label = normalizeEstimateQuoteDbText(item.label);
    if (!label) return;
    const match = text.includes(label)
      || (label.includes("구조") && text.includes("구조"))
      || (label.includes("마감") && text.includes("마감"))
      || (label.includes("토목") && (text.includes("토목") || text.includes("조경")))
      || (label.includes("인테리어") && (text.includes("인테리어") || text.includes("철거")))
      || (label.includes("골조성") && text.includes("골조성"));
    if (match) item.checked = true;
  });
}

function mergeEstimateQuoteDbMemo(row) {
  // 수주시 요청사항 컬럼은 상담 / 이메일 / 특기사항으로 통합했습니다.
  // 견적서 조건/용역내용과는 별도로 프로젝트 메모 성격으로만 사용합니다.
  return "";
}


function isEstimateDbPjMemoColumn(tab = estimateDbActiveTab, colIndex = 0) {
  return tab === "pj" && getEstimateDbColumnName(tab, colIndex) === "상담 / 이메일 / 특기사항";
}
function parseEstimateDbPjMemoCell(value) {
  const fallback = { callMemo: "", emailMemo: "", notes: "" };
  try {
    const raw = String(value || "").trim();
    if (!raw) return fallback;
    if (raw.startsWith("{")) return { ...fallback, ...JSON.parse(raw) };
    const parts = raw.split(/\n-{3,}\n/);
    if (parts.length >= 3) return { callMemo: parts[0] || "", emailMemo: parts[1] || "", notes: parts.slice(2).join("\n---\n") || "" };
    return { ...fallback, notes: raw };
  } catch (_) { return fallback; }
}
function stringifyEstimateDbPjMemoCell(obj = {}) {
  const data = {
    callMemo: String(obj.callMemo || ""),
    emailMemo: String(obj.emailMemo || ""),
    notes: String(obj.notes || "")
  };
  return JSON.stringify(data);
}
function summarizeEstimateDbPjMemoCell(value) {
  const data = parseEstimateDbPjMemoCell(value);
  return [
    data.callMemo ? `통화: ${data.callMemo}` : "",
    data.emailMemo ? `이메일: ${data.emailMemo}` : "",
    data.notes ? `특기: ${data.notes}` : ""
  ].filter(Boolean).join("\n");
}
function openEstimateDbPjMemoModal(rowIndex, colIndex) {
  const row = getEstimateDbRows()?.[rowIndex];
  const data = parseEstimateDbPjMemoCell(row?.[colIndex]);
  document.getElementById("estimateDbPjMemoModal")?.remove();
  const html = `
    <div class="quote-db-modal-backdrop" id="estimateDbPjMemoModal">
      <div class="quote-db-modal quote-db-pj-memo-modal">
        <div class="quote-db-modal-head">
          <h3>상담 / 이메일 / 특기사항</h3>
          <button type="button" class="btn btn-line btn-xs" onclick="closeEstimateDbPjMemoModal()">닫기</button>
        </div>
        <div class="quote-db-pj-memo-grid">
          <label>통화내용 기록<textarea id="estimateDbPjMemoCall" onkeydown="handleEstimateDbPjMemoModalKeydown(event)">${escapeEstimateDbHtml(data.callMemo)}</textarea></label>
          <label>중요 이메일 내용 기록<textarea id="estimateDbPjMemoEmail" onkeydown="handleEstimateDbPjMemoModalKeydown(event)">${escapeEstimateDbHtml(data.emailMemo)}</textarea></label>
          <label class="wide">견적 특기사항 / 착수 조건<textarea id="estimateDbPjMemoNotes" onkeydown="handleEstimateDbPjMemoModalKeydown(event)">${escapeEstimateDbHtml(data.notes)}</textarea></label>
        </div>
        <div class="quote-db-modal-actions">
          <button type="button" class="btn btn-primary" onclick="saveEstimateDbPjMemoModal(${rowIndex}, ${colIndex})">저장</button>
        </div>
      </div>
    </div>`;
  document.body.insertAdjacentHTML("beforeend", html);
  document.body.classList.add("quote-db-modal-open");
  requestAnimationFrame(() => document.getElementById("estimateDbPjMemoCall")?.focus());
}
function closeEstimateDbPjMemoModal() {
  document.getElementById("estimateDbPjMemoModal")?.remove();
  document.body.classList.remove("quote-db-modal-open");
}
function saveEstimateDbPjMemoModal(rowIndex, colIndex) {
  const value = stringifyEstimateDbPjMemoCell({
    callMemo: document.getElementById("estimateDbPjMemoCall")?.value || "",
    emailMemo: document.getElementById("estimateDbPjMemoEmail")?.value || "",
    notes: document.getElementById("estimateDbPjMemoNotes")?.value || ""
  });
  updateEstimateDbCell(rowIndex, colIndex, value, { commit: true, silentRender: true });
  closeEstimateDbPjMemoModal();
  renderEstimateDbManage();
  requestAnimationFrame(() => focusEstimateDbCell(rowIndex, colIndex));
}
function handleEstimateDbPjMemoModalKeydown(event) {
  if (event.key === "Escape") { event.preventDefault(); closeEstimateDbPjMemoModal(); }
  if (event.ctrlKey && String(event.key).toLowerCase() === "s") {
    event.preventDefault();
    const modal = event.currentTarget?.closest?.("#estimateDbPjMemoModal");
    const focused = document.activeElement;
    // save button remains available; Ctrl+S clicks it for quick entry.
    modal?.querySelector(".quote-db-modal-actions .btn-primary")?.click();
    focused?.focus?.();
  }
}

function applyEstimateDbPjRowToQuote(rowIndex) {
  if (estimateDbHasUnsavedChanges) commitEstimateDbPendingEdits({ silent: true });
  const row = estimateDbSheets?.pj?.rows?.[rowIndex];
  if (!row) {
    showToast("불러올 DB 행을 찾을 수 없습니다.");
    return;
  }

  syncEstimateQuoteInputsToState();
  const next = JSON.parse(JSON.stringify(estimateQuoteState));
  const assign = (key, value) => {
    const text = String(value || "").trim();
    if (text) next[key] = text;
  };

  assign("projectNo", getEstimateDbPjCell(row, "PJ NO"));
  assign("projectName", getEstimateDbPjCell(row, "프로젝트명"));
  assign("client", getEstimateDbPjCell(row, "거래처명"));
  assign("usage", getEstimateDbPjCell(row, "건물용도"));
  assign("areaM2", getEstimateDbPjCell(row, "연면적(m2)") || getEstimateDbPjCell(row, "연면적(㎡)"));
  assign("areaPy", getEstimateDbPjCell(row, "연면적(평)"));
  assign("floors", getEstimateDbPjCell(row, "층수"));
  assign("buildings", getEstimateDbPjCell(row, "동수"));
  assign("downloadUrl", getEstimateDbPjCell(row, "웹하드"));
  assign("webhardId", getEstimateDbPjCell(row, "ID"));
  assign("webhardPw", getEstimateDbPjCell(row, "PW"));
  assign("accessKey", getEstimateDbPjCell(row, "기타"));
  assign("folderName", getEstimateDbPjCell(row, "폴더명 / 자료위치"));
  assign("requesterName", getEstimateDbPjCell(row, "거래처담당자"));
  assign("requesterDept", [getEstimateDbPjCell(row, "부서명"), getEstimateDbPjCell(row, "직급")].filter(Boolean).join(" / "));
  assign("requesterPhone", getEstimateDbPjCell(row, "휴대폰") || getEstimateDbPjCell(row, "일반전화") || getEstimateDbPjCell(row, "직통전화"));
  assign("requesterEmail", getEstimateDbPjCell(row, "EMAIL") || getEstimateDbPjCell(row, "EMAIL2"));

  estimateQuoteState = next;
  setEstimateQuoteScopeByDbWorkType(getEstimateDbPjCell(row, "작업공종"));
  const dbMemo = mergeEstimateQuoteDbMemo(row);
  const richMemo = parseEstimateDbPjMemoCell(getEstimateDbPjCell(row, "상담 / 이메일 / 특기사항"));
  if (richMemo.callMemo && !estimateQuoteState.callMemo) estimateQuoteState.callMemo = richMemo.callMemo;
  if (richMemo.emailMemo && !estimateQuoteState.emailMemo) estimateQuoteState.emailMemo = richMemo.emailMemo;
  if (richMemo.notes && !estimateQuoteState.notes) estimateQuoteState.notes = richMemo.notes;
  if (dbMemo) {
    estimateQuoteState.notes = [estimateQuoteState.notes, dbMemo].filter(Boolean).join("\n\n");
  }
  estimateQuoteEditingIndex = null;
  closeEstimateQuoteDbImportModal();
  switchWorkPanel("estimateQuote");
  renderEstimateQuoteDashboard();
  showToast("DB관리의 PJ관리 행을 프로젝트 작성 화면으로 불러왔습니다.");
}

function getEstimateQuoteDbImportRows() {
  if (estimateDbHasUnsavedChanges) commitEstimateDbPendingEdits({ silent: true });
  const rows = estimateDbSheets?.pj?.rows || [];
  return rows
    .map((row, rowIndex) => ({ row, rowIndex }))
    .filter(({ row }) => ["PJ NO", "프로젝트명", "거래처명", "건물용도", "웹하드"].some(header => getEstimateDbPjCell(row, header)));
}

